#!/usr/bin/env python3
"""
MKT Original — 1 Kings chapters 3–5 (fill: verse-sparse chapters)
Run: python3 scripts/zc-original-1kings-fill-3-5.py

Covers missing verses:
  ch 3: v9, v28 exist; fills v1–8, v10–27  (26 missing)
  ch 4: v29 exists; fills v1–28, v30–34    (33 missing)
  ch 5: v4 exists; fills v1–3, v5–18       (17 missing)

MKT = Meaning-Knowledge-Translation: what the Hebrew says and means.

Key terms:
  lev shomea' (3:9) — listening/understanding heart, not abstract intellect
  chatnat Paroh (3:1) — Egyptian marriage alliance, a political liability
  ba-mot (3:2-3) — high places, legitimate before temple but theologically charged
  mas (5:13) — conscripted/forced labor, echoes Egyptian bondage
  arez/berosh (5:8) — cedar/cypress, the prestige timber of the ancient world
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ONE_KINGS_ORIGINAL = {
    "3": {
        "1": "<p><b>v1 — Solomon's Egyptian marriage alliance</b><br><i>Va-yitchaten Shlomo et-Par'oh melekh Mitzrayim</i> — 'Solomon made himself a son-in-law to Pharaoh king of Egypt.' The verb <i>chatnat</i> (to become a son-in-law) is the diplomatic idiom for a marriage alliance. The marriage signals Solomon's international standing — Egypt's pharaohs rarely gave daughters to foreign kings; this is an exceptional diplomatic achievement. But the narrator places it first in Solomon's reign as an ominous shadow: Deuteronomy 17:17 warns kings against multiplying wives, and Egypt is the place Israel escaped from. The city of David serves as provisional housing until construction projects are finished.</p>",
        "2": "<p><b>v2 — The people sacrifice at the high places</b><br>The narrator offers a historical note: the people were sacrificing at the <i>ba-mot</i> (high places), because no house for the name of the LORD had yet been built. The <i>ba-mot</i> were elevated outdoor cult sites — the standard place of worship throughout Canaan. Before the temple, they were tolerated; after the temple's construction, continued use of high places becomes the standard indictment of kings (nearly every king of Israel and Judah is evaluated in relation to high-place worship). This verse anticipates the temple and excuses the pre-temple practice without fully endorsing it.</p>",
        "3": "<p><b>v3 — Solomon loved the LORD — except at the high places</b><br>The double characterization: <i>'Va-ye'ehav Shlomo et-YHWH lalekheth be-chuqqot David aviv'</i> — 'Solomon loved the LORD, walking in the statutes of his father David.' Then the qualification: <i>'raq ba-ba-mot hu mevazach u-meqatter'</i> — 'except (only) at the high places he sacrificed and burned incense.' The word <i>raq</i> (only/except) is the Deuteronomist's characteristic hedge — <i>raq</i> introduces the flaw that shadows an otherwise positive assessment. Solomon's love for YHWH is real, but his worship practice has not yet been centralized. This verse is a miniature of his whole career: genuine piety with compromising exceptions.</p>",
        "4": "<p><b>v4 — The king at Gibeon: a thousand burnt offerings</b><br>Gibeon (<i>Giv'on</i>), northwest of Jerusalem, housed the tabernacle and the bronze altar at this period (cf. 1 Chr 16:39; 21:29). It was the legitimate pre-temple worship center — <i>ha-ba-mah ha-gedolah</i> (the great high place). Solomon offers a thousand burnt offerings there — a massive dedication, expressing both wealth and piety. The sheer scale (a thousand <i>olot</i>) marks this as a royal act of extraordinary devotion. The Lord's appearance at Gibeon in a dream-vision (<i>chalom ha-lailah</i>) responds to this act of generosity.</p>",
        "5": "<p><b>v5 — The dream-theophany at Gibeon</b><br><i>'Va-yera YHWH el-Shlomo ba-chalom ha-lailah'</i> — 'The LORD appeared to Solomon in the night in a dream.' The <i>chalom</i> (dream) as a medium of divine communication is well-established in the Hebrew Bible (cf. Gen 20:3; 28:12; 37:5; Num 12:6). The formula <i>sh'al mah etten lakh</i> ('Ask — what shall I give you?') is the divine patronage question, an open invitation. Solomon's response (vv6-9) is what defines his reign: given an open-ended divine offer, what does he ask for?</p>",
        "6": "<p><b>v6 — Solomon recalls David's hesed before asking</b><br>Solomon's prayer begins not with his request but with a recitation of divine faithfulness: <i>'Attah asita im-avdekha David avi hesed gadol'</i> — 'You showed your servant David my father great steadfast love (<i>hesed</i>).' He grounds his petition in the covenant loyalty God showed David, which David repaid with <i>emunah</i> (faithfulness), <i>tzedaqah</i> (righteousness), and <i>yesherut levav</i> (uprightness of heart). Solomon is doing something theologically sophisticated: before asking for anything, he establishes the relational context. His request will be an extension of the covenant, not a new transaction.</p>",
        "7": "<p><b>v7 — I am only a young man who does not know how to lead</b><br><i>'Ve-anokhi na'ar qatan lo yeda'ti tzeit uvo'</i> — 'I am but a young man; I do not know how to go out or come in.' The phrase <i>na'ar qatan</i> (young/small lad) is a humility formula — not necessarily about literal age (Solomon is probably in his twenties) but about experience and capacity relative to the task. <i>Tzeit uvo'</i> (going out and coming in) is a Hebrew idiom for public leadership, military command, and administration (cf. Num 27:17; Josh 14:11). Solomon's confession of inadequacy is the proper disposition before the gift of wisdom. Pride would disqualify; humility opens the request.</p>",
        "8": "<p><b>v8 — Your servant stands in the midst of your great people</b><br><i>'Ve-avdekha be-tokh ammekha asher bacharta'</i> — 'Your servant stands in the midst of your chosen people (<i>am asher bacharta</i>).' The term <i>bachar</i> (choose/elect) marks Israel as covenantally chosen — not just a large nation but a people with a specific relationship to YHWH. The size of the people — <i>asher lo yimmaneih ve-lo yissafer me-rov</i> (too numerous to count or number) — echoes the Abrahamic promise (Gen 13:16; 22:17). Solomon is saying: the stakes of this task are covenantal, not merely political. He needs wisdom adequate to govern a people who belong to God.</p>",
        "10": "<p><b>v10 — God is pleased with Solomon's request</b><br><i>'Va-yitav ha-davar be-einei Adonai'</i> — 'The thing was good in the eyes of the Lord.' The phrase <i>tov be-einei</i> (good in the eyes of) is the standard expression for divine approval. What pleases God is not just what Solomon asked for (wisdom) but what he did not ask for: long life, riches, or the death of his enemies. The three items not asked for are precisely what kings typically pursue — three temptations of power that Solomon, in his best moment, declines. The request reveals character: what you ask for when offered anything says more about you than what you do when you have it.</p>",
        "11": "<p><b>v11 — Because you asked for discernment, not long life or wealth</b><br>God's response names the three alternatives Solomon rejected: <i>'arokh yamim'</i> (long life), <i>'osher'</i> (wealth), and <i>'nefesh oyevecha'</i> (the life of your enemies). Instead Solomon asked for <i>binah</i> (discernment/understanding) to hear judgment. The word <i>binah</i> (from <i>byn</i> — to distinguish/discern between) is one of the Hebrew wisdom vocabulary's key terms, alongside <i>chokhmah</i> (wisdom) and <i>da'at</i> (knowledge). <i>Binah</i> specifically involves discriminating judgment — the capacity to tell right from wrong, just from unjust. This is exactly the judicial wisdom a king needs most.</p>",
        "12": "<p><b>v12 — A wise and discerning heart beyond all who came before or after</b><br><i>'Hineh natati lekha lev chakham ve-navon'</i> — 'Behold, I give you a wise (<i>chakham</i>) and discerning (<i>navon</i>) heart.' The pairing <i>chakham-navon</i> is a standard wisdom doublet (cf. Deut 1:13; 4:6; Prov 1:5). Then the superlative claim: none before Solomon had this measure of wisdom; none after him will. The comparison functions to establish the unique character of the Solomonic era. The wisdom of Solomon's reign is not simply useful competence but a singular gift that defines an unrepeatable moment in Israel's history.</p>",
        "13": "<p><b>v13 — What you did not ask: wealth and honor</b><br>In addition to wisdom, God adds what Solomon did not ask: <i>osher ve-khavod</i> (wealth and honor) such that no other king compares all his days. This follows a wisdom tradition principle: those who seek wisdom gain what they did not seek (Prov 3:16 — 'Long life is in her right hand; in her left hand are riches and honor'). Wisdom-seeking is rewarded with the very things that wise men decline to grasp at directly. Solomon's example in the dream will become a paradigm: seek the right thing and the rest follows.</p>",
        "14": "<p><b>v14 — Long life conditional on obedience</b><br>The one thing Solomon did not ask for — long life — God grants conditionally: <i>'ve-im telekh be-derakhay lishmore chuqqotai u-mitzvotai ke-asher halakh David avikha'</i> — 'if you walk in my ways to keep my statutes and commandments as David your father did, I will lengthen your days.' The conditionality is important: the other gifts (wisdom, wealth, honor) appear unconditional; long life is conditional on covenant obedience. This foreshadows Solomon's later failures — the long life promised is conditioned on faithfulness Solomon ultimately does not fully maintain.</p>",
        "15": "<p><b>v15 — Solomon awakes: the dream is real; offerings before the ark</b><br>Solomon awakes and recognizes it was a dream (<i>va-yiqatz Shlomo ve-hineh chalom</i>). But the dream-theophany is not dismissed as mere fantasy — it is the medium through which God has spoken. Solomon's response is to go immediately to Jerusalem and stand before the ark of the covenant of the LORD. The ark is the locus of divine presence — the place where Moses spoke with God (Exod 25:22). Solomon offers <i>olot</i> (burnt offerings) and <i>shelamim</i> (peace/fellowship offerings) and makes a feast for all his servants. The dream becomes public liturgy.</p>",
        "16": "<p><b>v16 — Two women, both zonot, come before the king</b><br><i>'Az tavo'na shtei nashim zonot el ha-melekh'</i> — 'Then two women who were prostitutes came to the king.' The word <i>zonah</i> (prostitute) is legally and socially marginal — these women have no father or husband to represent them in court. They come directly to the king, which implies Solomon's courts are accessible even to the most vulnerable. The case they bring is about motherhood, which transcends their social status. The juxtaposition is pointed: the king just received divine wisdom; here is the first test of it, brought by the most marginal litigants possible.</p>",
        "17": "<p><b>v17 — The first woman's testimony: shared house, shared birth</b><br>The first woman's account: she and this woman (<i>ha-ishah ha-zot</i>) share a house; she gave birth while they were together. The intimacy of shared quarters makes the situation both plausible (witnesses are absent) and legally unresolvable by normal means — no one else was present (v18: 'we were alone — there was no stranger in the house'). The setting is domestic, the dispute intimate, the stakes absolute: a living child and a dead one, and no one knows whose is which.</p>",
        "18": "<p><b>v18 — No third party present: 'just the two of us in the house'</b><br><i>'Ve-ein zar ittanu ba-bayit zulati shetayim anachnu va-bayit'</i> — 'There was no stranger with us in the house — just the two of us in the house.' The repetition of <i>ba-bayit</i> (in the house) underscores the hermetically closed evidentiary situation. No witness, no corroborating evidence. The case is structurally undecidable by ordinary legal methods — two contradictory first-person accounts with zero external verification. This is precisely the kind of case that requires the <i>lev shomea'</i> — a hearing heart that perceives beyond testimony.</p>",
        "19": "<p><b>v19 — The dead child: rolled over in the night</b><br>The first woman continues: this woman's son died in the night because <i>'shakhav'</i> — she lay on him (i.e., accidentally suffocated him in sleep). Infant death by rolling (<i>shakhav</i>) is attested in ancient sources and was a feared danger for mothers who co-slept with infants. The accusation is not murder but negligence leading to death. The dead baby then becomes the object of the dispute — the question is whose death this is and whose life the surviving child has.</p>",
        "20": "<p><b>v20 — The switch in the night</b><br>The accusation: 'She arose at midnight and took my son from beside me while I slept (<i>va-anachti yeshena</i>), and placed him in her bosom and placed her dead son in my bosom.' The switch is made in the dark while the first woman is asleep. When she wakes to nurse, she finds a dead child — and recognizes in the morning light that it is not her son. The whole accusation rests on her recognition of the children, which the second woman disputes. The story is a legal riddle about identity, recognition, and maternal knowledge.</p>",
        "21": "<p><b>v21 — Morning recognition: this is not my son</b><br>The first woman examines the dead child in the morning light: <i>'va-hitbonen elaiv ve-hineh lo-hayah beni asher yaladti'</i> — 'I examined him carefully and behold, he was not my son whom I had borne.' The verb <i>hitbonen</i> (to examine carefully/discern) is from the same root as <i>binah</i> — the wisdom Solomon just received. The irony is delicate: the woman's careful discernment of her own child is the problem that requires Solomon's discernment to resolve.</p>",
        "22": "<p><b>v22 — The other woman denies it: direct verbal conflict</b><br><i>'Vatomer ha-ishah ha-acheret lo ki beni ha-chai u-vinekh ha-met'</i> — 'The other woman said: No! My son is the living one and your son is the dead one.' The back-and-forth denial (<i>va-tomer zot…va-tomer zot</i>) is a legal impasse — each woman makes the identical claim with equal insistence. The king now has two contradictory, unverifiable testimonies. Normal judicial tools (witnesses, oath, physical evidence) cannot resolve this. What Solomon has received in the dream must now prove itself.</p>",
        "23": "<p><b>v23 — The king states the problem precisely</b><br>Solomon articulates the legal deadlock: each woman says the living child is hers and the dead one is the other's. The statement of the problem with such clarity is itself part of wisdom — the king is not confused; he has understood the structure of the dispute. What follows is not a guess but a deliberate diagnostic move: the sword is proposed not as a solution but as a test that will reveal the truth through the reactions of the two women.</p>",
        "24": "<p><b>v24 — Bring me a sword</b><br><i>'Havi'u li charev'</i> — 'Bring me a sword.' The command is stark and single-word in Hebrew. A sword is brought before the king. Solomon's request creates a crisis: if both women are lying (or both telling the truth), neither has an obvious reaction. But Solomon's insight into maternal love means he knows that a true mother will respond differently to the threat against her child than a woman who has no stake. The sword is a psychological probe, not an execution order.</p>",
        "25": "<p><b>v25 — Cut the living child in two: give half to each</b><br><i>'Gizru et ha-yeled ha-chai li-shenayim ve-tenu et-hachetzi le-achat ve-et-hachetzi le-achat'</i> — 'Cut the living child in two and give half to one and half to the other.' The command is a reductio ad absurdum: if the child cannot be undivided, divide it. But the command is designed to make the real mother reveal herself — she cannot remain silent at the threat of her child's death. A woman who would accept half a dead child rather than surrender the child alive has already shown she has no maternal investment.</p>",
        "26": "<p><b>v26 — The real mother speaks: her womb burned for her son</b><br><i>'Va-tomer ha-ishah asher benah ha-chai el ha-melekh ki nikhmertu rachameha al-benah'</i> — 'The woman whose son was the living one said to the king, for her womb burned (<i>nikhmertu</i>) for her son.' The word <i>rachamim</i> (womb/compassion — the Hebrew root for both maternal organ and maternal feeling) is here in its visceral sense: her gut, her womb, convulsed. She pleads: 'Give her the living child! Do not kill him!' The other woman, by contrast, says 'Let it be divided' — the tell that she has no stake in this child's life.</p>",
        "27": "<p><b>v27 — The verdict: give him to the first woman; she is his mother</b><br><i>'Ve-ya'an ha-melekh va-yomer…tenu lo et ha-yeled ha-chai…hi imo'</i> — 'The king answered and said: Give the living child to the first woman; do not kill him — she is his mother.' The verdict needs no lengthy reasoning. The behavioral evidence is conclusive: the woman who sacrificed her claim to save the child's life is its mother. The woman who accepted death rather than surrender the child to a rival is the one who lost her own son. Solomon has used proposed violence as a truth-disclosure mechanism, not a genuine threat.</p>",
        "28": "<p><b>v28 — All Israel heard and feared: the wisdom of God in him</b><br><i>'Ki ra'u ki chokhmah Elohim be-qirbo la'asot mishpat'</i> — 'For they saw that the wisdom of God was in him to do justice (<i>mishpat</i>).' The verdict's effect is not mere admiration for cleverness but awe (<i>va-yir'u</i> — they feared) at the divine gift at work. The wisdom is recognized as being <i>Elohim's</i> — not Solomon's personal brilliance but God's wisdom operating through him. This connects the dream-gift to the real-world outcome: what God promised in the night at Gibeon, all Israel witnessed in the daylight court at Jerusalem.</p>"
    },
    "4": {
        "1": "<p><b>v1 — Solomon king over all Israel</b><br><i>'Va-yehiy ha-melekh Shlomo melekh al-kol-Yisrael'</i> — 'And King Solomon was king over all Israel.' The tautological statement ('the king was king') is a formal literary marker opening the administrative section of Solomon's reign. The phrase <i>kol-Yisrael</i> (all Israel) is the Deuteronomist's standard for unified monarchy — north and south together, all twelve tribes under one crown. The administrative lists that follow explain how this unity was maintained in practice.</p>",
        "2": "<p><b>v2 — The chief officials list opens with the priest</b><br>The list of <i>sarim</i> (officials/princes) begins with Azariah son of Zadok the priest. Starting with the priest signals that the administrative structure of the Solomonic state integrates cultic and civil authority. Zadok was David's loyal high priest (2 Sam 15:24-29); his son Azariah's position at the head of Solomon's court shows dynastic continuity in the priesthood alongside the monarchy. This is the same Zadokite priesthood whose lineage will be idealized in Ezekiel 40-48.</p>",
        "3": "<p><b>v3 — Scribes and recorder</b><br>Elihoreph and Ahijah sons of Shisha were <i>soferim</i> (scribes/secretaries) — the literate administrators who managed official correspondence and documentation. Jehoshaphat son of Ahilud was the <i>mazkir</i> (recorder/herald) — an office that combined royal chronicler, public announcer, and spokesman. Both offices reflect the bureaucratic apparatus of a developed state with written records, parallel to Egyptian and Mesopotamian administrative models. The presence of professional scribes indicates the expansion of literacy and documentation in Solomon's administration.</p>",
        "4": "<p><b>v4 — Army commander and priests</b><br>Benaiah son of Jehoiada commands the army (<i>al ha-tzava</i>) — he had previously executed Joab and Shimei for David at Solomon's command (1 Kings 2). His loyalty made him the natural successor as military chief. Zadok and Abiathar appear together as priests, though Abiathar had been exiled to Anathoth for supporting Adonijah (1 Kings 2:26-27). His continued appearance on the official list may reflect that the list predates his exile, or that he retained a nominal title. The two-priest formula mirrors David's administration (2 Sam 8:17; 20:25).</p>",
        "5": "<p><b>v5 — Azariah over the district officers; Zabud the king's friend</b><br>Azariah son of Nathan oversees the twelve district officers — the regional administrators who will be listed in vv8-19. The title <i>nitzav</i> (district officer/overseer) refers to Solomon's provincial governors, who cut across traditional tribal boundaries. More notable is Zabud son of Nathan: he is called <i>kohen</i> (priest) and <i>re'eh ha-melekh</i> (the king's personal friend/companion — a technical court title). The 're'eh' was a specific royal advisory position, attested in Egyptian parallels, indicating personal access and counsel beyond official duties.</p>",
        "6": "<p><b>v6 — Household administrator and forced-labor officer</b><br>Ahishar is over the <i>bayit</i> (royal household/palace administration) — the domestic economy of the palace, provisioning, and maintenance. Adoniram son of Abda is over the <i>mas</i> (forced labor / conscripted labor). The term <i>mas</i> is the same word used for the slave labor Israel performed in Egypt (Exod 1:11). Solomon's use of the same institution reverses Israel's foundational identity as escaped slaves — now Israel itself (and especially subjugated Canaanites, per 1 Kings 9:20-21) performs forced labor for the king. This is the first shadow of the critique that will culminate in ch12.</p>",
        "7": "<p><b>v7 — Twelve district governors for monthly provision rotation</b><br>Solomon appoints twelve <i>nitzavim</i> (district officers) over all Israel whose function is to supply provisions for the king and his household, each district responsible for one month of the year. The twelve-district system is reorganization of Israel according to economic function rather than tribal geography — some districts align with tribes, others do not. The rotation ensures that the burden is spread evenly (no district bears the full year's cost) but also that the palace has a constant, reliable supply chain. This is empire-building administrative logic.</p>",
        "8": "<p><b>v8 — Ben-hur in the hill country of Ephraim</b><br>The district list uses patronymic identifiers (Ben-X = 'son of X') for several officers, suggesting they are known by lineage rather than personal name, or that their names were not preserved. Ben-hur's district in the hill country of Ephraim covers the central highland — agriculturally productive, strategically central, and tribally the most powerful region of the north. That an Ephraimite district exists as a royal administrative unit (rather than a tribal autonomous zone) shows Solomon's centralizing project at work.</p>",
        "9": "<p><b>v9 — Ben-deker in the Shephelah region</b><br>Ben-deker's district covers Makaz, Shaalbim, Beth-shemesh, and Elon-beth-hanan — the Shephelah (foothills) west of Jerusalem toward the Philistine plain. Beth-shemesh is a well-known border town (Judg 13:25; 1 Sam 6:12) that served as a transit point between coastal plain and highlands. The Shephelah was agricultural lowland producing grain and olives — essential provision for the palace system.</p>",
        "10": "<p><b>v10 — Ben-hesed in Arubboth</b><br>Ben-hesed's district includes Arubboth with Socoh and all the land of Hepher — the northern Shephelah and coastal plain, running from the hills toward the Sharon plain. The land of Hepher appears also in the territorial lists of Joshua (Josh 12:17) and in Numbers as part of Manasseh's territory (Num 26:32). This district straddles the border between traditional Manassehite and unallocated territory, showing that Solomon's administration overrides tribal lines.</p>",
        "11": "<p><b>v11 — Ben-abinadab in Naphath-dor; royal marriage connection</b><br>Ben-abinadab administers Naphath-dor, the coastal plain around Dor — a strategically important harbor city on the Mediterranean. Notably, he is Solomon's son-in-law, having married Solomon's daughter Taphath. The marriage of district officers into the royal family is a mechanism of loyalty — governors tied by kinship to the center are less likely to defect or build independent power bases. The Solomonic system combines administrative efficiency with dynastic control through marriage.</p>",
        "12": "<p><b>v12 — Baana son of Ahilud in the Jezreel valley</b><br>Baana son of Ahilud administers Taanach, Megiddo, and the Beth-shean corridor — the Jezreel valley and its key strategic cities. This is the most militarily significant district: Megiddo commanded the pass through the Carmel ridge (the site of major battles throughout history), and Beth-shean guarded the Jordan valley crossing. The administrative scope runs from Jezreel through the valley to the Jordan — the breadth of the best agricultural land in Israel.</p>",
        "13": "<p><b>v13 — Ben-geber in Ramoth-gilead: Transjordan</b><br>Ben-geber governs Ramoth-gilead in Transjordan, including the villages of Jair (Manasseh) and the region of Argob in Bashan — sixty great cities with bronze bars (walls). The Transjordanian territories are the most recently pacified and most ethnically mixed; governing them requires an officer with both military and administrative capacity. Argob in Bashan corresponds roughly to the Hauran — fertile volcanic plateau, valuable for agriculture and strategic depth east of the Jordan.</p>",
        "14": "<p><b>v14 — Ahinadab in Mahanaim</b><br>Mahanaim ('Two camps') was the site of Jacob's angel encounter (Gen 32:2) and David's refuge during Absalom's rebellion (2 Sam 17:24). Its strategic position east of the Jordan near the Jabbok ford made it an important administrative center for central Transjordan. Ahinadab's single-verse mention follows the terse pattern of this list: name, assignment, nothing more. The list's brevity mirrors the bureaucratic nature of the information — efficient, functional, without narrative development.</p>",
        "15": "<p><b>v15 — Ahimaaz in Naphtali; another royal son-in-law</b><br>Ahimaaz governs Naphtali — the far north, the territory that runs along the Sea of Galilee and into the Upper Galilee highlands. Like Ben-abinadab (v11), Ahimaaz is a royal son-in-law, married to Solomon's daughter Basemath. Naphtali will later be one of the first territories taken by Aram and then Assyria (2 Kings 15:29) — its northern exposure makes it a strategic frontier requiring loyal administration.</p>",
        "16": "<p><b>v16 — Baanah in Asher and Bealoth</b><br>Baanah son of Hushai (likely son of David's spy Hushai the Archite — 2 Sam 15:32) governs Asher and Bealoth — the coastal plain from Carmel northward, Phoenician borderland. Asher's territory ran along the Mediterranean coast toward Tyre and Sidon, making this district commercially important for trade with Phoenicia — precisely the relationship Solomon will exploit in chapter 5 for timber procurement.</p>",
        "17": "<p><b>v17 — Jehoshaphat in Issachar</b><br>Jehoshaphat son of Paruah governs Issachar — the southeastern Jezreel valley and the hills south of it, fertile grain country. Issachar's tribal blessing in Gen 49:14-15 describes the tribe as 'a strong donkey crouching between two burdens,' willing to work the land under foreign pressure. The district corresponds roughly to the plain of Esdraelon, one of the most productive agricultural zones in the country.</p>",
        "18": "<p><b>v18 — Shimei in Benjamin</b><br>Shimei son of Ela governs Benjamin — the tribal territory immediately north and east of Jerusalem, the very heartland of the kingdom. Governing Benjamin (Saul's tribe, historically resistant to Davidic rule) with a loyal appointee is politically sensitive. The appointment of a governor over Benjamin rather than allowing tribal self-governance shows the extent to which Solomon's administrative reforms centralized power away from tribal structures.</p>",
        "19": "<p><b>v19 — Geber in Gilead; one governor over the whole land</b><br>Geber son of Uri in Gilead (the territory of Sihon and Og, the Amorite kingdoms Moses defeated) and one additional governor over all the land. The note about a single governor over the whole land (<i>nitzav echad asher ba-aretz</i>) is cryptic — it may refer to an overall provincial coordinator, or to a special district not otherwise listed, or Judah itself (which notably appears nowhere in the district list, possibly because it was exempt from the provision levy). The question of whether Judah paid provincial taxes is a historical puzzle the text leaves unresolved.</p>",
        "20": "<p><b>v20 — Judah and Israel as numerous as sand; contentment and security</b><br><i>'Yehudah ve-Yisrael rabbim ka-chol asher al-ha-yam'</i> — 'Judah and Israel were as numerous as the sand that is by the sea.' The fulfillment of Abrahamic promise (Gen 22:17; 32:12) is explicitly evoked. The phrase <i>'okhlim ve-shotim ve-sameichim'</i> (eating and drinking and rejoicing) describes covenant blessing actualized: the people are fed, secure, and glad. The combination of fulfilled promise and material wellbeing marks this as the Solomonic golden age — the high point from which subsequent chapters measure decline.</p>",
        "21": "<p><b>v21 — Solomon rules from the Euphrates to Egypt; tribute paid</b><br>The empire's extent: from the Euphrates (<i>ha-nahar</i>) to the land of the Philistines and to the border of Egypt. This precisely corresponds to the land promised to Abraham (Gen 15:18: 'from the river of Egypt to the great river, the Euphrates'). <i>Massu u-vadu</i> — 'paying tribute and serving him.' This is hegemonic empire: vassal kings pay tribute but retain local governance. The Abrahamic territorial promise, given in Gen 15 but only partially realized in Joshua, reaches its maximum extent under Solomon. The narrative presents this as a covenantal fulfillment moment.</p>",
        "22": "<p><b>v22 — Daily provisions: thirty cors of flour</b><br>Solomon's daily provisions begin to be listed: thirty <i>kor</i> of fine flour (<i>solet</i>) and sixty kor of ordinary flour (<i>qemach</i>). A <i>kor</i> (homer) is approximately 220 liters — thirty cors of fine flour alone is about 6,600 liters daily. The quantities are staggering by any standard. The provision list that follows (vv22-23) gives a concrete picture of the scale of the palace economy: this is not a simple household but a state institution consuming enormous quantities of food daily.</p>",
        "23": "<p><b>v23 — Oxen, cattle, sheep, deer, gazelles, and choice fowl</b><br>Ten fattened oxen (<i>baqar avusim</i>), twenty pasture-fed cattle (<i>baqar re'i</i>), a hundred sheep (<i>tzon</i>), plus deer (<i>ayalim</i>), gazelles (<i>tzeviot</i>), roebucks (<i>yachmur</i>), and choice fattened fowl. The variety signals royal luxury: domesticated livestock is supplemented by hunted game, and ordinary provisions by delicacies. The list reads like a royal banquet menu rather than a simple daily tally — the point is abundance and variety as markers of Solomon's prosperity and the empire's resources.</p>",
        "24": "<p><b>v24 — Dominion west of the Euphrates; peace on all sides</b><br><i>'Ki hu rodeh be-khol-ever ha-nahar'</i> — 'For he had dominion over all the region west (<i>ever</i>) of the Euphrates.' The word <i>ever</i> (side/region) gives Aramaic-speakers the name for the western province: 'Abar Nahara' (Across the River) — later the Persian satrapy name. <i>'Ve-shalom hayah lo mi-kol-evadav savio'</i> — 'And he had peace from all his neighbors on all sides.' Peace as the mark of covenant blessing (Lev 26:6: 'I will give peace in the land') is Solomon's defining political achievement.</p>",
        "25": "<p><b>v25 — Each man under his vine and fig tree, Dan to Beersheba</b><br><i>'Va-yeshev Yehudah ve-Yisrael lavetach…ish tachat gafno ve-tachat te'enato'</i> — 'Judah and Israel lived in safety, each man under his vine and fig tree.' The phrase 'under his vine and fig tree' is the quintessential biblical image of security and prosperity (Mic 4:4; Zech 3:10; cf. Rev 22). Dan to Beersheba — the traditional northern and southern limits of Israelite territory — frames the peace as encompassing all of the land. This verse is the peak of the Solomonic narrative's idealized portrait.</p>",
        "26": "<p><b>v26 — Forty thousand horse stalls and twelve thousand horsemen</b><br>Solomon had forty thousand stalls for chariot horses (<i>susim le-markavto</i>) and twelve thousand horsemen (<i>parashim</i>). Deuteronomy 17:16 explicitly prohibits the king from multiplying horses or returning to Egypt for horses. The scale of Solomon's cavalry establishment — the largest in the ancient Near East at this time — directly violates this command. The narrator records the fact without immediate comment, but the Deuteronomic law hangs over the description: Solomon's military power is built precisely on what the Torah forbade.</p>",
        "27": "<p><b>v27 — District officers supply the palace without lack</b><br>The twelve district officers fulfill their provision obligation to King Solomon and all who come to his table, each in his month. Nothing is lacking (<i>lo ye'adder davar</i>). The efficiency of the provision system is its own commendation: the administrative machinery works. But the human cost — thirty thousand Israelites conscripted for labor (ch5), twelve districts taxed monthly — is the shadow behind the adequacy.</p>",
        "28": "<p><b>v28 — Barley and straw for the horses</b><br>They also bring barley (<i>se'orah</i>) and straw (<i>teven</i>) for the horses and swift steeds (<i>ha-rekesh</i>) to the designated places. The feeding of the royal cavalry requires a separate supply chain beyond the human food provision. The agricultural output of twelve districts feeds both the palace and its military infrastructure. The detail is prosaic but significant: empire runs on logistics, and Solomon's empire has mastered that logistics at scale.</p>",
        "30": "<p><b>v30 — Solomon's wisdom exceeded all the sages of the east and Egypt</b><br><i>'Va-tereb chokhmah Shlomo me-chokhmah kol-benei qedem u-mikol chokhmah Mitzrayim'</i> — 'Solomon's wisdom exceeded the wisdom of all the sons of the east and all the wisdom of Egypt.' The <i>benei qedem</i> (sons of the east) refers to the wisdom traditions of Mesopotamia, Arabia, and the Transjordanian regions — the famous wise men of the ancient world. Egypt's wisdom tradition was the oldest and most developed in the ancient Near East. Surpassing both is a way of claiming the highest conceivable wisdom for Solomon.</p>",
        "31": "<p><b>v31 — Wiser than Ethan, Heman, Chalcol, and Darda</b><br>Named comparators: Ethan the Ezrahite (possibly the author of Psalm 89), Heman (possibly the author of Psalm 88), Chalcol, and Darda — sons of Mahol. These figures are legendary wise men of Israelite tradition; some appear in 1 Chronicles 2:6 as descendants of Judah through Zerah. The comparison presupposes a known wisdom tradition with recognized exemplars. Solomon surpasses them all. <i>Va-yehi shmo be-khol-ha-goyim saviv</i> — 'His fame was in all the surrounding nations.' Wisdom generates international reputation.</p>",
        "32": "<p><b>v32 — Three thousand proverbs; one thousand and five songs</b><br>Solomon composed three thousand <i>meshalim</i> (proverbs/sayings/comparisons) and one thousand and five <i>shirim</i> (songs). The numbers are traditionally large — a way of expressing inexhaustible literary output. The book of Proverbs contains far fewer than three thousand sayings attributed to Solomon; the tradition assumes a larger Solomonic corpus, most of which has not been preserved. <i>Mashal</i> covers not just proverbs but parables, allegories, and comparative wisdom forms — the breadth of the genre matches the breadth of Solomon's knowledge.</p>",
        "33": "<p><b>v33 — Botanical and zoological knowledge from cedar to hyssop</b><br>Solomon spoke about plant life (<i>vayedaber al-ha-etzim</i>) from the cedar of Lebanon (<i>erez ha-Levanon</i> — the prestige tree of the ancient world) to the hyssop (<i>ezov</i>) growing from the wall — the smallest, most humble plant. He spoke about animals (<i>behemah</i>), birds (<i>of</i>), reptiles (<i>remes</i>), and fish (<i>dagah</i>). This is encyclopedic natural knowledge, the ancient equivalent of natural philosophy. The range from cedar to hyssop (large to small) and through four animal categories represents comprehensive creation-knowledge — the wisdom of the creature-world as a whole.</p>",
        "34": "<p><b>v34 — Nations send to hear Solomon's wisdom</b><br><i>'Va-yavo'u mi-kol-ha-ammim lishmo'a et chokhmah Shlomo'</i> — 'They came from all peoples to hear the wisdom of Solomon, sent by all the kings of the earth who had heard of his wisdom.' The wisdom draws international pilgrimage: Solomon becomes a destination, not just a power. The Queen of Sheba's visit (ch10) is the narrative expansion of this summary. The phrase <i>kol-malkhei ha-aretz</i> (all the kings of the earth) is hyperbolic but intended to capture the universal scope of Solomon's reputation. Wisdom at its peak draws the world toward Israel.</p>"
    },
    "5": {
        "1": "<p><b>v1 — Hiram king of Tyre sends to Solomon</b><br>Hiram (<i>Chiram</i>) of Tyre hears that Solomon has been anointed king in place of David and sends his servants — the diplomatic mission that will launch the temple timber partnership. Hiram is identified as one who had <i>ohev David</i> (loved David) throughout his days — the word <i>ohev</i> (love) is the diplomatic term for a treaty-relationship or alliance. The Phoenician-Israelite alliance predates Solomon; Hiram had supplied David with cedar for his palace (2 Sam 5:11). This is a relationship Solomon inherits and will use to far greater effect.</p>",
        "2": "<p><b>v2 — Solomon responds to Hiram's embassy</b><br>The narrative compresses the diplomatic exchange: Hiram sends, and Solomon sends back (<i>va-yishlach Shlomo el-Chiram</i>). Solomon's letter is quoted in vv3-6, a formal diplomatic communication explaining his purpose and his need. The genre is ancient royal correspondence — similar in structure and tone to letters found in the Amarna archive and other ANE diplomatic collections. Solomon presents himself as the appropriate continuation of David's relationship with Hiram.</p>",
        "3": "<p><b>v3 — David could not build because of war</b><br>Solomon rehearses to Hiram why David did not build the temple: <i>'attah yadata et David avi ki lo yakhal livnot bayit le-shem YHWH Elohav mipnei ha-milchamah'</i> — 'You know that David my father could not build a house for the name of the LORD his God because of the wars on every side.' The formal reason is war: God told David that because he had shed much blood (<i>damim rabbim shafakht</i>), he would not build the temple (1 Chr 22:8; 28:3). Solomon is explaining this to Hiram as part of establishing that Solomon, not David, is the appropriate temple-builder — and the time is now right.</p>",
        "5": "<p><b>v5 — I intend to build a house for the name of the LORD</b><br><i>'Va-ani amad livnot bayit le-shem YHWH Elohai'</i> — 'And I intend to build a house for the name of the LORD my God.' The phrase <i>le-shem YHWH</i> (for the name of the LORD) is the Deuteronomic formula for legitimate worship centralization — the temple is the place where God's name dwells (Deut 12:5, 11; 14:23). The formula <i>le-shem</i> (for the name) rather than 'for the presence' or 'for the glory' reflects a sophisticated theology: God's presence is mediated through his name, not located in the building itself. Solomon then cites the Davidic promise from 2 Sam 7: 'Your son whom I will set on your throne shall build the house for my name.'</p>",
        "6": "<p><b>v6 — Give orders for cedars; I will pay your wages</b><br>The practical request: <i>'Tzaveh ve-yikhretu-li arzim min-ha-Levanon'</i> — 'Give orders for the cutting of cedars from Lebanon for me.' Cedar (<i>erez</i>) was the prestige building material of the ancient Near East — Phoenicia's major export product. Solomon's servants will work alongside Hiram's, and Solomon will pay whatever wages Hiram sets. The acknowledgment that 'you know there is no one among us who knows how to cut timber like the Sidonians' (<i>ki ein banu yode'a lichtov etzim ka-Tzidoniim</i>) is diplomatic honesty that also justifies the partnership. Israel has no timber and no woodcutters skilled in this work.</p>",
        "7": "<p><b>v7 — Hiram rejoices greatly; blesses the LORD</b><br><i>'Va-yishmach Chiram me'od va-yomer Barukh YHWH ha-yom'</i> — 'Hiram rejoiced greatly and said: Blessed be the LORD today.' A Phoenician king blesses YHWH — this is significant. Hiram does not convert or confess YHWH as sole God, but he acknowledges the covenant between YHWH and David as the ground of this partnership: 'who has given David a wise son over this great people.' The blessing formula (<i>barukh YHWH</i>) is standard Hebrew liturgical language; Hiram's use of it may reflect diplomatic courtesy or genuine recognition, but the narrator records it without qualification.</p>",
        "8": "<p><b>v8 — Hiram accepts: I will supply all you desire</b><br>Hiram's formal acceptance: he has received Solomon's message and will do all that Solomon desires regarding cedar (<i>arez</i>) and cypress (<i>berosh</i>) timber. The pairing of cedar and cypress appears throughout the temple-building narrative — cedar for structural beams and paneling, cypress for flooring and doors. The specific species (<i>berosh</i> = probably Cupressus sempervirens or possibly juniper) were complementary in their working properties and both unavailable in Israel's hill country.</p>",
        "9": "<p><b>v9 — Rafts floated from Lebanon to the sea; Israel will pay</b><br>The logistics: Hiram's servants will cut logs from Lebanon, bring them down to the sea (<i>ha-yam</i>), and float them as rafts (<i>dobarot</i> — log-rafts lashed together) to whatever location Solomon designates, where they will be disassembled and Solomon's servants will take them inland. The maritime timber trade is well-documented in the ancient world — Phoenician coastal expertise in sea-transport was the complement to their forestry. Hiram's request in return is that Solomon provide provisions for his household (<i>natan mzon le-veiti</i>).</p>",
        "10": "<p><b>v10 — Hiram supplied all the cedar and cypress Solomon desired</b><br><i>'Va-yiten Chiram el-Shlomo atzei arzim va-atzei broshim kol-cheftzoh'</i> — 'Hiram supplied Solomon with cedar and cypress timber, all his desire.' The brief summary of the exchange highlights the completeness of Hiram's fulfillment: <i>kol cheftzoh</i> (all his desire). In narrative terms, this signals that the material foundation of the temple is secured. The logistical challenge of moving massive timber from Lebanese forests to Jerusalem's heights is accomplished through the Phoenician partnership — something Israel could not have done alone.</p>",
        "11": "<p><b>v11 — Solomon gives Hiram wheat and oil annually</b><br>Solomon gives Hiram twenty thousand <i>kor</i> of wheat (<i>chittim</i>) for his household and twenty thousand <i>kor</i> of pure beaten olive oil (<i>shemen katit</i>). The <i>shemen katit</i> (pressed/beaten oil — the highest quality, cold-pressed from hand-beaten olives) is distinguished from ordinary lamp oil. The quantities — twenty thousand cors each of grain and oil annually — represent a substantial fraction of Israelite agricultural surplus going to Phoenicia. This is the Solomonic economy at work: timber north, grain and oil south, sustained as long as the temple project runs.</p>",
        "12": "<p><b>v12 — The LORD gave Solomon wisdom; a treaty of peace between them</b><br><i>'Va-YHWH natan chokhmah li-Shlomo ka'asher diber lo'</i> — 'The LORD gave Solomon wisdom as he had promised him.' The Gibeon dream-promise is now being fulfilled in the international arena: the wisdom given there is expressed here in successful diplomacy. <i>'Va-yihi shalom bein Chiram u-vein Shlomo va-yikhredu berit shneihem'</i> — 'There was peace between Hiram and Solomon, and the two of them made a covenant (<i>berit</i>).' The formal treaty (<i>berit</i>) between Israel and Phoenicia is both commercial and diplomatic, a formal alliance that will be renewed and fatefully extended in Ahab's marriage to Jezebel (1 Kings 16).</p>",
        "13": "<p><b>v13 — Solomon conscripts thirty thousand Israelites for forced labor</b><br><i>'Va-ya'al ha-melekh Shlomo mas mi-kol-Yisrael'</i> — 'King Solomon raised (<i>ya'al</i>) forced labor (<i>mas</i>) from all Israel — thirty thousand men.' The word <i>mas</i> (corvée/forced labor) again — this time explicitly applied to Israelites. The same term used for Egyptian slave labor, the same institution from which the Exodus liberated Israel, is now deployed by Israel's own king. The thirty thousand figure is massive. The narrative does not comment editorially, but the resonance with Exodus is unmistakable and will be made explicit in ch 12 when the northern tribes demand relief from this burden.</p>",
        "14": "<p><b>v14 — Monthly rotation: one month in Lebanon, two months home</b><br>The rotation system: ten thousand men per month to Lebanon, two months at home. Adoniram (<i>Adoram</i>) is in charge of the mas. The rotation (one-in-three months in Lebanon) means any individual Israelite spends one third of the year doing royal labor in foreign forests. The organizational logic is relatively humane — rest periods are built in — but the compulsory nature and scale (30,000 men) make it a heavy imposition. Adoniram will be stoned by the northern tribes at Rehoboam's accession (1 Kings 12:18) — his role as corvée administrator makes him the face of the grievance.</p>",
        "15": "<p><b>v15 — Seventy thousand carriers and eighty thousand stonecutters</b><br>In addition to the thirty thousand Israelite woodcutters sent to Lebanon, Solomon has seventy thousand <i>savel</i> (burden-bearers/carriers) and eighty thousand <i>chotzev</i> (stonecutters) in the hill country. The numbers — 180,000 laborers in total — are enormous. Most scholars understand these as primarily drawn from the Canaanite population (explicitly stated in 1 Kings 9:20-22 — Canaanite remnants as permanent forced laborers, while Israelites serve as soldiers, officers, and commanders). The distinction matters for the ch12 narrative: it is Israelite corvée that sparks the revolt, not Canaanite.</p>",
        "16": "<p><b>v16 — Three thousand three hundred supervisors</b><br>Three thousand three hundred <i>sarim ha-nitzavim</i> (officer-overseers) supervised the workers. The supervision-to-labor ratio (1 supervisor per ~55 workers) reflects serious organizational scale. The 2 Chronicles parallel (2 Chr 2:2) says 3,600 supervisors — a well-known discrepancy probably due to different counting methods or textual transmission. The supervisory class represents Solomon's middle management: below the district officers, above the laborers, essential to translating royal ambition into physical construction.</p>",
        "17": "<p><b>v17 — Large, expensive stones for the foundation</b><br>At the king's command, they quarry large, expensive (<i>yeqarot</i> — precious/costly) stones to lay the foundation of the temple with <i>avnei gazit</i> (dressed/cut stone). The <i>avnei gazit</i> (ashlar masonry — stones cut square with a saw) contrasts with the fieldstone construction of ordinary buildings. The archaeological record confirms massive ashlar construction at Solomon's Megiddo, Hazor, and Gezer — the 'six-chambered gates' attributed to this period show precisely this kind of monumental stonework. The temple's foundation was built to last.</p>",
        "18": "<p><b>v18 — Three teams of builders: Israelite, Phoenician, and Gebalite</b><br>Solomon's builders, Hiram's builders, and the men of Gebal (<i>Gebalim</i>) cut and prepared timber and stones for the building. Gebal (Byblos in Greek — modern Jbeil in Lebanon) was an ancient Phoenician city famous for craftsmen and stonecutters, and gives its name to the Greek <i>biblos</i> (book) through its role as a papyrus trading center. Three-nation collaboration — Israel for the project, Tyre for timber and maritime logistics, Byblos for skilled stonecutting — reflects the international scope of what Solomon is building. The temple is a monument that could only exist at the intersection of Solomonic wealth, Phoenician skill, and prophetic commission.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', '1kings')
    merge_comm(existing, ONE_KINGS_ORIGINAL)
    save_comm('mkt-original', '1kings', existing)
    import json
    from pathlib import Path
    ROOT_V = Path(__file__).resolve().parent.parent
    il = json.loads((ROOT_V / 'data/interlinear/1kings.json').read_text())
    all_ok = True
    for ch in ['3', '4', '5']:
        got = set(existing.get(ch, {}).keys())
        need = set(il[ch].keys())
        missing = need - got
        if missing:
            print(f'  ch{ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch{ch}: {len(got)} verses complete')
    if all_ok:
        print('1 Kings original fill (chs 3-5) done. All verses present.')

if __name__ == '__main__':
    main()
